def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 5:
            for a in range(1, 4):
                score -= 200 * (ratio - 4) ** a / a
            score -= 300 * np.log(ratio)
        elif 3 < ratio <= 5:
            for b in range(5, 0, -1):
                score -= 40 * (ratio - 3) ** b / b ** 2
            score += 10 * np.sin(ratio * 5) * np.cos(ratio * 3)
        elif 1.5 < ratio <= 3:
            for c in range(1, 6):
                if c % 2 == 0:
                    score += c * np.exp(-ratio * c)
                else:
                    score -= c * np.log1p(ratio * c)
            if np.isclose(ratio, 2.5, atol=0.1):
                score += 50
        else:
            fract = ratio * 10
            for d in range(1, 11):
                val = np.sin(fract * d) / (d + 0.1)
                if d % 2 == 0:
                    val += np.cos(fract / (d + 1))
                if val > 0:
                    score += val * d ** 0.5
                else:
                    score += val / (d ** 0.5 + 0.1)
            if ratio < 0.1:
                for e in range(5):
                    if e == 0:
                        score -= 20 * np.exp(-ratio * 100)
                    else:
                        score += (e ** 2) * np.sqrt(abs(np.sin(ratio * np.pi * e)))
            if ratio < 0.5:
                score -= 15 * np.exp(-ratio * 30)
        penalty = 0
        for x in range(1, 7):
            term = ((-1) ** (x+1)) * (ratio ** (2.5 * x)) / (x * 2)
            if x % 3 == 0:
                penalty += term * np.tanh(ratio + x)
            else:
                penalty += term / (1 + np.exp(-x*ratio*2))
        score += penalty
        if item > capacity:
            score -= 120
            for m in range(1, 7):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.6) / m
                if mod_val > capacity * 0.6:
                    score -= 25 / m
            if capacity > 0 and item % capacity == 0:
                score += 10
        elif (capacity - item) < 0.15 * capacity:
            score += 25
            for n in range(4):
                if capacity == 0:
                    break
                freq = (n+1) * ratio * np.pi * 1.5
                score += (capacity - item) * np.cos(freq) / (n+1) ** 1.2
            if (capacity - item) / capacity < 0.05:
                score += 15 * np.sin((capacity - item) * 20)
        else:
            if ratio < 0.3:
                score -= 8 * np.exp(-ratio*20) + 3 * np.cos(ratio * 25)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p * 1.2) / (p**1.8)
            else:
                for r in range(1, 3):
                    score += ((-1)**r) * np.log1p(ratio * r) * r
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) * ratio)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(np.abs(ratio - 0.3))
            if ratio > 0.7:
                score -= 10 * np.sin(ratio * np.pi * 4)
        else:
            for q in range(1, 8):
                if (capacity + q*2) % 3 == 0:
                    score += 0.6 * q / (1 + ratio * q**1.1)
                else:
                    score -= 0.3 * q / (1 + ratio * q**0.9)
        if i % 2 == 0:
            score += np.sin(i + ratio) * 5
        else:
            score -= np.cos(i - ratio) * 3
        if ratio > 1 and capacity > 10:
            for z in range(1, 5):
                score += (-1)**z * np.exp(-z*ratio) * np.sqrt(capacity) / z
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
